from typing import List


def max_area(height: List[int]) -> int:
    left = 0
    right = len(height) - 1
    best = 0

    while left < right:
        width = right - left
        area = width * min(height[left], height[right])
        if area > best:
            best = area

        if height[left] < height[right]:
            left += 1
        else:
            right -= 1

    return best


if __name__ == "__main__":
    print(max_area([1, 8, 6, 2, 5, 4, 8, 3, 7]))
    print(max_area([1, 1]))
